import{_ as e,o as a,c as t,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"天眼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/天眼.md","filePath":"4.资源分区/7.物品与装备/4.奇物/6.可升级/天眼.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/6.可升级/天眼.md"};function o(p,b,l,i,_,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"天眼",tabindex:"-1"},[n("天眼 "),r("a",{class:"header-anchor",href:"#天眼","aria-label":'Permalink to "天眼"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),s('<h1 id="天眼-1" tabindex="-1">天眼 <a class="header-anchor" href="#天眼-1" aria-label="Permalink to &quot;天眼&quot;">​</a></h1><p>天眼<br> 奇物<br> 占据头部位<br> 科技本质<br> C+1000<br> 介绍：前文明的科技造物，曾服役于各个领域<br> 直到最后，因第七次世界大战，导致世界重启，该科技也消弭于历史重长河之中，不过好在，该科技在零号避难所内还有原型<br> 可由于缺乏能源，城市也陷入死寂<br> 经过千年的沉寂，零号避难所终于迎来了一批将该城市重新启动的人，而这台原型机也因此再次浮现于世人眼前<br> 【天眼部署】【侦测-洞悉】【集成解析】<br> 【天眼部署】：为了方便个体操控天眼系统，轮回者可以准备佩戴特殊的脑机接口，其外观酷似耳机，会占据耳朵位置<br> 当轮回者与天眼进行神经同步后，天眼会环绕使用者悬浮，进入战斗轮后，天眼会自动部署<br> 【侦测-洞悉】<br> 当天眼存在于你身周时，如果有单位被你精确定位，那么天眼会你提供实时演算数据，针对这些目标，天眼将额外提供12点高速，如果高速有溢出，则可以将最多5点高速转化为攻击上的dp加值<br> 被精确定位的单位如果被你攻击命中，你可以花费一个自由动作进行解析（智力-洞察-解析），对方以潜藏进行对抗，如果解析对抗成功，你将会知道自身的破防有无溢出，这视为D级信息来源解析效果<br> 【集成解析】<br> 被精确定位的单位如果被解析或者读心过，那么针对该目标，你可以将最多6点高速转化为破甲或者破魔（同时只能选择其一转化）</p><p>战争之眼<br> 奇物<br> 科技本质<br> B+2000（差升）<br> 介绍：零号避难所重新启动后，为应对战时需要，代号【零】的人工智能重启了多项已被废除的防卫协议，其中便有战争之眼计划<br> 天眼部署后，保留原有特性情况下，额外获得下列特性<br> 【锁定】【危险预警】【侦测-洞悉】<br> 【侦测-洞悉】<br> 在原有特性上，针对被精确定位的目标，你对其的攻击加骰等级提升一级，最多不超过8加骰<br> 【锁定】<br> 战争之眼会持续标记已经被精确定位的目标，轮回者可以使用一个自由动作指定一个处于你敏感范围内被精确单位的目标，战争之眼将记录数据，并持续锁定该目标<br> 如果该目标被你或者你的队友解析或者读心，那么战争之眼将进入锁定模式<br> 被锁定的目标，哪怕对方躲入掩体，战争之眼都会根据对方行为逻辑，进行数据库对比，预测目标接下来将会出现到哪里，这视为一种真实视觉效果<br> 每次只能指定一个单位<br> 【危险预警】<br> 如果存在被解析/读心的单位对你发起攻击，那么面对这次攻击，你获得基于天生防御的【劣化1】</p><p>天眼卫星<br> 奇物<br> 科技本质<br> A+4000（差升）<br> 介绍：随着轮回者的到访次数增加，战争之眼也被轮回者想尽办法拐回主神空间，经过主神空间优化，数据如下<br> 天眼部署后，保留原有特性，以下特性出现更新<br> 【天眼部署】【危险预警】【侦测-洞悉】【集成解析】<br> 【天眼部署】<br> 现在，如果条件允许，你可以将天眼部署至高空几千米的位置，&#39;&#39;这仅仅是画风效果<br> 【危险预警】<br> 如果存在被解析/读心的单位对你发起攻击，那么面对这次攻击，你获得基于洞察防御的【劣化2】和【洞彻】效果<br> 【侦测-洞悉】<br> 当天眼存在于你身周时，如果有单位被你精确定位，那么天眼会你提供实时演算数据，针对这些目标，天眼将额外提供16点高速，如果高速有溢出，则可以将最多6点高速转化为攻击上的dp加值<br> 【集成解析】<br> 被精确定位的单位如果被解析或者读心过，那么针对该目标，你可以将最多12点高速转化为破甲或者破魔</p><p>锁定打击<br> 技艺<br> 科技本质<br> A+4000<br> 动作：迅捷<br> 持续：一轮<br> 通过对敌方数据的分析，你的每一次攻击都能精准命中敌方防御动作的薄弱点<br> 针对被精确定位的目标进行攻击时，视为拥有【威仪】特性，并额外获得20点高速，如果高速有溢出，则可以将最多10点高速转化为攻击上的dp加值<br> 如果有单位被你解析/读心，针对该单位进行攻击时，你可以忽视对方的格挡防御，这视为A级信息来源效果</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=e(d,[["render",o]]);export{f as __pageData,m as default};
